import { useEffect } from "react";

const visionStyles = `*,*::before,*::after{box-sizing:border-box;margin:0;padding:0}
html{scroll-behavior:smooth}
body{background:#08080f;overflow-x:hidden}
.vision-section{position:relative;min-height:100vh;display:flex;align-items:center;overflow:hidden;border-bottom:.5px solid var(--border);padding:104px 56px 72px;isolation:isolate}
/* video layer */
.vision-video{position:absolute;inset:0;width:100%;height:100%;object-fit:cover;z-index:-3;background:#0a0814;
  /* feather edges into the page on all sides */
  -webkit-mask-image:linear-gradient(90deg,transparent 0,#000 14%,#000 86%,transparent 100%),linear-gradient(180deg,transparent 0,#000 12%,#000 84%,transparent 100%);
  -webkit-mask-composite:source-in;mask-image:linear-gradient(90deg,transparent 0,#000 14%,#000 86%,transparent 100%),linear-gradient(180deg,transparent 0,#000 12%,#000 84%,transparent 100%);mask-composite:intersect;
  opacity:.92;transition:opacity 1.2s ease}
.vision-video.fade-in{opacity:.92}
/* dark scrim so text stays readable + brand color wash */
.vision-section::before{content:'';position:absolute;inset:0;z-index:-2;pointer-events:none;
  background:linear-gradient(90deg,rgba(8,8,15,.96) 0%,rgba(8,8,15,.82) 34%,rgba(8,8,15,.30) 64%,rgba(8,8,15,.55) 100%)}
.vision-section::after{content:'';position:absolute;inset:0;z-index:-2;pointer-events:none;
  background:radial-gradient(ellipse 60% 50% at 78% 46%,rgba(124,58,237,.18),transparent 70%),
             linear-gradient(180deg,rgba(8,8,15,.7) 0%,transparent 18%,transparent 80%,rgba(8,8,15,.95) 100%)}
.vision-inner{max-width:1180px;margin:0 auto;width:100%;position:relative;z-index:2}
.vision-copy{max-width:620px}
.vision-eyebrow{font-size:10px;font-weight:700;letter-spacing:.22em;text-transform:uppercase;color:#cda349;margin-bottom:20px;display:flex;align-items:center;gap:12px}
.vision-eyebrow::before{content:'';width:34px;height:1px;background:linear-gradient(90deg,#cda349,transparent)}
.vision-title{font-family:'Barlow Condensed',sans-serif;font-weight:800;font-size:clamp(36px,4.6vw,64px);line-height:.94;text-transform:uppercase;letter-spacing:-.01em;color:#fff;margin-bottom:28px;text-shadow:0 2px 30px rgba(0,0,0,.6)}
.vision-title em{font-style:normal;background:linear-gradient(120deg,#e9c873,#a87c2e 60%,#f3dd9a);-webkit-background-clip:text;background-clip:text;color:transparent}
.vision-quote{font-family:'Barlow Condensed',sans-serif;font-weight:700;font-size:clamp(21px,2.4vw,30px);line-height:1.24;color:#f1eeff;border-left:2px solid #cda349;padding-left:24px;margin-bottom:26px;max-width:560px;text-shadow:0 2px 20px rgba(0,0,0,.5)}
.vision-quote span{color:#cda349}
.vision-body{font-size:15px;line-height:1.85;color:rgba(241,238,255,.7);max-width:480px}
.vision-tags{display:flex;flex-wrap:wrap;gap:11px;margin-top:34px}
.vision-tag{font-size:10.5px;font-weight:700;letter-spacing:.1em;text-transform:uppercase;color:#e0c06a;padding:8px 16px;border:.5px solid rgba(205,163,73,.4);border-radius:40px;background:rgba(13,12,26,.5);backdrop-filter:blur(6px);transition:background .25s,border-color .25s,color .25s,transform .25s}
.vision-tag:hover{background:rgba(205,163,73,.16);border-color:rgba(205,163,73,.65);color:#f3dd9a;transform:translateY(-2px)}
/* reveal entrance for copy */
.vision-copy{opacity:0;transform:translateY(28px);transition:opacity .9s ease,transform .9s cubic-bezier(.2,.8,.2,1)}
.vision-section.visible .vision-copy{opacity:1;transform:none}
@media(prefers-reduced-motion:reduce){.vision-video{animation:none}}
@media(max-width:760px){
  .vision-section{padding:96px 32px 72px;min-height:auto}
  .vision-section::before{background:linear-gradient(180deg,rgba(8,8,15,.85),rgba(8,8,15,.92))}
  .vision-body{max-width:100%}
}
.brand-mark{display:block;filter:drop-shadow(0 0 10px rgba(124,58,237,.45));transition:transform .35s ease,filter .35s ease;background-image:var(--logo);background-size:contain;background-repeat:no-repeat;background-position:center}
.brand-mark-lg{width:30px;height:30px}
.brand-mark-sm{width:24px;height:24px}
.logo:hover .brand-mark{transform:rotate(-6deg) scale(1.06);filter:drop-shadow(0 0 16px rgba(159,95,255,.7))}



/* SCI-FI ENERGY CORE */
.vision-core{position:absolute;top:50%;right:0%;transform:translateY(-50%);
  width:min(54vw,640px);max-width:50%;z-index:1;pointer-events:none;
  opacity:0;transition:opacity 1.8s ease}
.vision-section.visible .vision-core{opacity:1}
.vision-core svg{width:100%;height:auto;display:block;overflow:visible}
/* center everything on (280,200) */
.sc-rot{transform-box:view-box;transform-origin:280px 200px}
/* containment rings rotate at different speeds/axes (faked 3D via scaleY) */
.vision-section.visible .sc-ringA{animation:scSpin 18s linear infinite}
.vision-section.visible .sc-ringB{animation:scSpinR 26s linear infinite}
.vision-section.visible .sc-ringC{animation:scSpin 34s linear infinite}
.vision-section.visible .sc-gimbal{animation:scSpinR 12s linear infinite}
@keyframes scSpin{from{transform:rotate(0)}to{transform:rotate(360deg)}}
@keyframes scSpinR{from{transform:rotate(0)}to{transform:rotate(-360deg)}}
/* draw-in for rings */
.sc-ring{stroke-dasharray:1400;stroke-dashoffset:1400}
.vision-section.visible .sc-ring{animation-name:scDraw;animation-duration:2s;animation-timing-function:ease;animation-fill-mode:forwards}
.vision-section.visible .sc-ringA{animation:scDraw 2s ease .4s forwards, scSpin 18s linear 2.4s infinite}
.vision-section.visible .sc-ringB{animation:scDraw 2s ease .6s forwards, scSpinR 26s linear 2.6s infinite}
.vision-section.visible .sc-ringC{animation:scDraw 2s ease .8s forwards, scSpin 34s linear 2.8s infinite}
@keyframes scDraw{to{stroke-dashoffset:0}}
/* reactor orb pulse */
.vision-section.visible .sc-orb{animation:scOrb 3.2s ease-in-out 1s infinite}
@keyframes scOrb{0%,100%{opacity:.85;transform:scale(1)}50%{opacity:1;transform:scale(1.06)}}
.sc-orb{transform-box:fill-box;transform-origin:center}
/* energy halo breathing */
.vision-section.visible .sc-halo{animation:scHalo 4s ease-in-out infinite}
@keyframes scHalo{0%,100%{opacity:.3;transform:scale(.92)}50%{opacity:.7;transform:scale(1.08)}}
.sc-halo{transform-box:fill-box;transform-origin:center}
/* scan line sweeping down the core */
.vision-section.visible .sc-scan{animation:scScan 3.5s linear 1.4s infinite}
@keyframes scScan{0%{transform:translateY(-46px);opacity:0}10%{opacity:.9}90%{opacity:.9}100%{transform:translateY(46px);opacity:0}}
.sc-scan{transform-box:fill-box}
/* energy bolts flicker */
.vision-section.visible .sc-bolt{animation:scBolt 2.6s steps(2) infinite}
@keyframes scBolt{0%,72%,100%{opacity:0}74%,86%{opacity:.85}}
/* hologram flicker on whole core */
.vision-section.visible .sc-holo{animation:scFlicker 7s steps(40) infinite}
@keyframes scFlicker{0%,96%,100%{opacity:1}97%{opacity:.82}98%{opacity:1}99%{opacity:.9}}
/* particles twinkle */
.sc-cap{filter:drop-shadow(0 0 5px rgba(159,95,255,.9))}
.sc-cap.g{filter:drop-shadow(0 0 6px rgba(0,234,255,.9))}
/* tick labels fade */
.sc-label{opacity:0;font-family:'Barlow Condensed',sans-serif;font-weight:700;letter-spacing:.18em;text-transform:uppercase}
.vision-section.visible .sc-label{animation:scFade 1s ease 2.2s forwards}
@keyframes scFade{to{opacity:.92}}
/* HUD corner brackets pulse */
.vision-section.visible .sc-hud{animation:scHud 4s ease-in-out infinite}
@keyframes scHud{0%,100%{opacity:.35}50%{opacity:.75}}
@media(prefers-reduced-motion:reduce){
  .vision-core *{animation:none!important;stroke-dashoffset:0!important;opacity:1!important;transform:none!important}
  .vision-section.visible .vision-core{opacity:1}
}
@media(max-width:980px){.vision-core{display:none}}
/* FINAL POLISH PASS */
/* clear fixed nav+subnav when jumping to anchors */
#overview,#liquidity,#vision,#protocol,#technology,section[id]{scroll-margin-top:128px}
html{scroll-behavior:smooth}
/* the vision section is full-height & centered, so its own padding handles clearance; keep larger margin */
#vision{scroll-margin-top:112px}
/* subtle consistent transition on all interactive links */
a{transition:color .2s ease}
/* prevent any accidental horizontal scroll from glows/animations */
body{overflow-x:hidden}`;

