const VisionSection = () => {
  useEffect(() => {
    const section = document.getElementById("vision");
    const video = section?.querySelector<HTMLVideoElement>(".vision-video");

    if (!section || !video) return;

    video.muted = true;
    video.defaultMuted = true;

    const tryPlay = () => {
      const playPromise = video.play();
      if (playPromise) playPromise.catch(() => {});
    };
    const revealVideo = () => video.classList.add("fade-in");
    const observer = new IntersectionObserver(
      (entries) => {
        entries.forEach((entry) => {
          if (entry.isIntersecting) {
            section.classList.add("visible");
            tryPlay();
          }
        });
      },
      { threshold: 0.15 },
    );
    const interactionEvents = ["pointerdown", "keydown", "touchstart", "scroll"] as const;
    const resumeOnInteraction = () => tryPlay();

    observer.observe(section);
    video.addEventListener("loadeddata", revealVideo);
    video.addEventListener("canplay", tryPlay);
    window.addEventListener("load", tryPlay);
    interactionEvents.forEach((event) =>
      window.addEventListener(event, resumeOnInteraction, { passive: true, once: true }),
    );
    tryPlay();

    return () => {
      observer.disconnect();
      video.removeEventListener("loadeddata", revealVideo);
      video.removeEventListener("canplay", tryPlay);
      window.removeEventListener("load", tryPlay);
      interactionEvents.forEach((event) =>
        window.removeEventListener(event, resumeOnInteraction),
      );
    };
  }, []);

  return (
    <>
      <style>{visionStyles}</style>
      <div dangerouslySetInnerHTML={{ __html: visionMarkup }} />
    </>
  );
};

export default VisionSection;
